.root {
}

.moment-list {
  display: flex;
  justify-content: center;
  padding: 8rem 0;
}

.moment-list__list {
  display: flex;
  flex-direction: column;
  gap: 2rem;
  width: 75%;
}

.moment-list__bg-wrap {
  position: fixed;
  inset: 0;
  background-color: black;
}

.moment-list__bg-img {
  width: 100%;
  height: 160vh;
  opacity: 0.4;
